async ({ path }) => {
  if (isNavigationPath(path)) {
    throw createError({ statusCode: 404, message: 'Page not found' })
  }

  const event = useEvent()
  const config = useRuntimeConfig(event)
  const publicConfig = config.public
  const siteUrl = getRequestURL(event).origin || inferSiteURL()
  const baseURL = config.app?.baseURL || '/'

  const availableLocales = getAvailableLocales(publicConfig)
  const collectionName = publicConfig.i18n?.locales
    ? getCollectionFromPath(path, availableLocales)
    : 'docs'

  try {
    const page = await queryCollection(event, collectionName as keyof Collections)
      .where('path', '=', path)
      .select('title', 'path', 'description')
      .first()

    if (!page) {
      throw createError({ statusCode: 404, message: 'Page not found' })
    }

    const content = await event.$fetch<string>(`/raw${path}.md`)

    return {
      title: page.title,
      path: page.path,
      description: page.description,
      content,
      url: siteUrl ? joinURL(siteUrl, baseURL, page.path) : joinURL(baseURL, page.path),
    }
  }
  catch (error) {
    if ((error as { statusCode?: number }).statusCode === 404) throw error
    throw createError({ statusCode: 500, message: 'Failed to get page' })
  }
}

async ({ locale }) => {
  const event = useEvent()
  const config = useRuntimeConfig(event)
  const publicConfig = config.public

  const siteUrl = getRequestURL(event).origin || inferSiteURL()
  const baseURL = config.app?.baseURL || '/'
  const availableLocales = getAvailableLocales(publicConfig)
  const collections = getCollectionsToQuery(locale, availableLocales)

  try {
    const allPages = await Promise.all(
      collections.map(async (collectionName) => {
        const pages = await queryCollection(event, collectionName as keyof Collections)
          .where('path', 'NOT LIKE', '%.navigation')
          .select('title', 'path', 'description')
          .all()

        return pages.map(page => ({
          title: page.title,
          path: page.path,
          description: page.description,
          locale: collectionName.replace('docs_', ''),
          url: siteUrl ? joinURL(siteUrl, baseURL, page.path) : joinURL(baseURL, page.path),
        }))
      }),
    )

    return allPages.flat()
  }
  catch {
    throw createError({ statusCode: 500, message: 'Failed to list pages' })
  }
}

export function createImage(globalOptions: CreateImageOptions) {
  const ctx: ImageCTX = {
    options: globalOptions,
  }

  const getImage: $Img['getImage'] = (input: string, options = {}) => {
    const image = resolveImage(ctx, input, options)

    // Prerender static images
    if (import.meta.server && import.meta.prerender && globalOptions.event) {
      prerenderStaticImages(image.url, undefined, globalOptions.event)
    }

    return image
  }

  const $img = ((input, modifiers, options) => getImage(input, defu({ modifiers }, options)).url) as $Img

  for (const presetName in globalOptions.presets) {
    $img[presetName] = ((source, modifiers, options) =>
      $img(source, modifiers, { ...globalOptions.presets[presetName], ...options })) as $Img[string]
  }

  $img.options = globalOptions
  $img.getImage = getImage
  $img.getMeta = ((input: string, options?: ImageOptions) => getMeta(ctx, input, options)) as $Img['getMeta']
  $img.getSizes = ((input: string, options: ImageSizesOptions) => getSizes(ctx, input, options)) as $Img['getSizes']

  ctx.$img = $img as $Img

  return $img
}

const rawRefreshToken = useState<string | null>('auth:raw-refresh-token', () => null)
  if (config.refresh.isEnabled) {
    const _rawRefreshTokenCookie = useCookie<string | null>(config.refresh.token.cookieName, {
      default: () => null,
      domain: config.refresh.token.cookieDomain,
      maxAge: config.refresh.token.maxAgeInSeconds,
      sameSite: config.refresh.token.sameSiteAttribute,
      secure: config.refresh.token.secureCookieAttribute,
      httpOnly: config.refresh.token.httpOnlyCookieAttribute
    })

    // Set default value if `useState` returned `null`
    // https://github.com/sidebase/nuxt-auth/issues/896
    if (rawRefreshToken.value === null) {
      rawRefreshToken.value = _rawRefreshTokenCookie.value
    }

    watch(rawRefreshToken, () => {
      _rawRefreshTokenCookie.value = rawRefreshToken.value
    })

    // When the page is cached on a server, set the refresh token on the client
    if (instance) {
      onMounted(() => {
        if (_rawRefreshTokenCookie.value && !rawRefreshToken.value) {
          rawRefreshToken.value = _rawRefreshTokenCookie.value
        }
      })
    }
  }

// Re-construct state from cookie, also setup a cross-component sync via a useState hack, see https://github.com/nuxt/nuxt/issues/13020#issuecomment-1397282717
  const _rawTokenCookie = useCookie<string | null>(config.token.cookieName, {
    default: () => null,
    domain: config.token.cookieDomain,
    maxAge: config.token.maxAgeInSeconds,
    sameSite: config.token.sameSiteAttribute,
    secure: config.token.secureCookieAttribute,
    httpOnly: config.token.httpOnlyCookieAttribute
  })
  const rawToken = useState('auth:raw-token', () => _rawTokenCookie.value)
  watch(rawToken, () => {
    _rawTokenCookie.value = rawToken.value
  })

  const token = computed(() => formatToken(rawToken.value, config))
  function setToken(newToken: string | null) {
    rawToken.value = newToken
  }
  function clearToken() {
    setToken(null)
  }

  // When the page is cached on a server, set the token on the client
  if (instance) {
    onMounted(() => {
      if (_rawTokenCookie.value && !rawToken.value) {
        setToken(_rawTokenCookie.value)
      }
    })
  }

function mapNavigationItems(
  children: ContentNavigationItem[],
  files: ContentSearchFile[],
  parent?: ContentNavigationItem
): ContentSearchItem[] {
  // Build a path -> files index once per call to turn the per-leaf
  // `files.filter(...)` scan into an O(1) lookup. Without this, a large
  // navigation tree is O(leaves * files) on every re-map.
  const filesByPath = new Map<string, ContentSearchFile[]>()
  for (const file of files || []) {
    const basePath = file.id.split('#')[0] || file.id
    let bucket = filesByPath.get(basePath)
    if (!bucket) {
      bucket = []
      filesByPath.set(basePath, bucket)
    }
    bucket.push(file)
  }

  function visit(
    nodes: ContentNavigationItem[],
    ancestors: ContentNavigationItem[]
  ): ContentSearchItem[] {
    return nodes.flatMap((link) => {
      if (link.children?.length) {
        return visit(link.children, [...ancestors, link])
      }

      const matched = link.path ? filesByPath.get(link.path) : undefined
      return matched?.map(file => mapFile(file, link, ancestors)) || []
    })
  }

  return visit(children, parent ? [parent] : [])
}

export async function handlePkceVerifier(event: H3Event) {
  const query = getQuery<{ code?: string }>(event)

  // Create new verifier
  if (!query.code) {
    const verifier = encodeBase64Url(getRandomBytes())
    setCookie(event, 'nuxt-auth-pkce', verifier, {
      httpOnly: true,
      secure: !isDevelopment,
      sameSite: 'lax',
      maxAge: OAUTH_COOKIE_MAX_AGE,
      path: '/',
    })

    // Get pkce
    const encodedPkce = new TextEncoder().encode(verifier)
    const pkceHash = await subtle.digest('SHA-256', encodedPkce)
    const pkce = encodeBase64Url(new Uint8Array(pkceHash))

    return {
      code_verifier: verifier,
      code_challenge: pkce,
      code_challenge_method: 'S256',
    }
  }
  // If the verifier is in the cookie, get it from the cookie and delete the cookie
  const verifier = getCookie(event, 'nuxt-auth-pkce')
  deleteCookie(event, 'nuxt-auth-pkce')

  return { code_verifier: verifier }
}

export async function scanAndSyncOptions(nitro: Nitro) {
  // Scan plugins
  const scannedPlugins = await scanPlugins(nitro);
  for (const plugin of scannedPlugins) {
    if (!nitro.options.plugins.includes(plugin)) {
      nitro.options.plugins.push(plugin);
    }
  }

  // Scan tasks
  if (nitro.options.experimental.tasks) {
    const scannedTasks = await scanTasks(nitro);
    for (const scannedTask of scannedTasks) {
      if (scannedTask.name in nitro.options.tasks) {
        if (!nitro.options.tasks[scannedTask.name].handler) {
          nitro.options.tasks[scannedTask.name].handler = scannedTask.handler;
        }
      } else {
        nitro.options.tasks[scannedTask.name] = {
          handler: scannedTask.handler,
          description: "",
        };
      }
    }
  }

  // Scan modules
  const scannedModules = await scanModules(nitro);
  nitro.options.modules = nitro.options.modules || [];
  for (const modPath of scannedModules) {
    if (!nitro.options.modules.includes(modPath)) {
      nitro.options.modules.push(modPath);
    }
  }
}

export async function resolveVercelRuntime(nitro: Nitro) {
  // 1. Respect explicit runtime from nitro config
  let runtime: VercelServerlessFunctionConfig["runtime"] = nitro.options.vercel?.functions?.runtime;

  if (runtime) {
    // Already specified
    return runtime;
  }

  // 2. Read runtime from vercel.json if specified
  const vercelConfig = await readVercelConfig(nitro.options.rootDir);

  // 3. Use bun runtime if bunVersion is specified or bun used to build
  if (vercelConfig.bunVersion || "Bun" in globalThis) {
    runtime = "bun1.x";
  } else {
    // 3. Auto-detect runtime based on system Node.js version
    const systemNodeVersion = getSystemNodeVersion();
    const usedNodeVersion =
      SUPPORTED_NODE_VERSIONS.find((version) => version >= systemNodeVersion) ??
      SUPPORTED_NODE_VERSIONS.at(-1);
    runtime = `nodejs${usedNodeVersion}.x`;
  }

  // Synchronize back to nitro config
  nitro.options.vercel ??= {} as any;
  nitro.options.vercel!.functions ??= {} as any;
  nitro.options.vercel!.functions!.runtime = runtime;

  return runtime;
}

export async function buildFTSIndex<T extends PageCollectionItemBase>(
  db: DatabaseAdapter,
  collection: string,
  queryBuilder: CollectionQueryBuilder<T>,
  opts?: GenerateSearchSectionsOptions,
) {
  if (indexedCollections.has(collection)) {
    return
  }

  if (!ftsTableCreated) {
    await db.exec(`CREATE VIRTUAL TABLE IF NOT EXISTS ${FTS_TABLE} USING fts5(collection UNINDEXED, id UNINDEXED, title, title_normalized, titles UNINDEXED, content, level UNINDEXED)`)
    ftsTableCreated = true
  }

  const sections = await generateSearchSections(queryBuilder, opts)

  for (const section of sections) {
    const titleNormalized = section.title.replace(/([a-z])([A-Z])/g, '$1 $2')

    await db.exec(
      `INSERT INTO ${FTS_TABLE} (collection, id, title, title_normalized, titles, content, level) VALUES (?, ?, ?, ?, ?, ?, ?)`,
      [collection, section.id, section.title, titleNormalized, JSON.stringify(section.titles), section.content, section.level],
    )
  }

  indexedCollections.add(collection)
}

export function generateCollectionIndexStatements(collection: ResolvedCollection): string[] {
  if (!collection.indexes || collection.indexes.length === 0) {
    return []
  }

  const statements: string[] = []

  for (const index of collection.indexes) {
    // Validate columns exist in schema
    const invalidColumns = index.columns.filter(
      column => !collection.fields[column] && column !== 'id',
    )

    if (invalidColumns.length > 0) {
      logger.warn(
        `Index references non-existent column(s) "${invalidColumns.join(', ')}" in collection "${collection.name}". Skipping this index.`,
      )
      continue
    }

    // Generate index name
    const indexName = index.name || generateIndexName(collection.name, index.columns)

    // Quote column names for SQL safety
    const quotedColumns = index.columns.map(col => `"${col}"`).join(', ')

    // Build CREATE INDEX statement
    const uniqueKeyword = index.unique ? 'UNIQUE ' : ''
    const statement = `CREATE ${uniqueKeyword}INDEX IF NOT EXISTS ${indexName} ON ${collection.tableName} (${quotedColumns});`

    statements.push(statement)
  }

  return statements
}

function chainablePromise<T extends keyof PageCollections, Result>(event: H3Event, collection: T, fn: (qb: CollectionQueryBuilder<PageCollections[T]>) => Promise<Result>) {
  const queryBuilder = queryCollection(event, collection)

  const chainable: ChainablePromise<T, Result> = {
    where(field, operator, value) {
      queryBuilder.where(String(field), operator, value)
      return chainable
    },
    andWhere(groupFactory) {
      queryBuilder.andWhere(groupFactory)
      return chainable
    },
    orWhere(groupFactory) {
      queryBuilder.orWhere(groupFactory)
      return chainable
    },
    order(field, direction) {
      queryBuilder.order(String(field), direction)
      return chainable
    },
    then(onfulfilled, onrejected) {
      return fn(queryBuilder).then(onfulfilled, onrejected)
    },
    catch(onrejected) {
      return this.then(undefined, onrejected)
    },
    finally(onfinally) {
      return this.then(undefined, undefined).finally(onfinally)
    },
    get [Symbol.toStringTag]() {
      return 'Promise'
    },
  }

  return chainable
}

function resolveVueComponent(component: string | Renderable) {
  let _component: unknown = component
  if (typeof component === 'string') {
    if (htmlTags.has(component)) {
      return component
    }
    if (globalComponents.includes(pascalCase(component))) {
      _component = resolveComponent(component, false)
    }
    else if (localComponents.includes(pascalCase(component))) {
      const loader = localComponentLoaders[pascalCase(component) as keyof typeof localComponentLoaders]
      _component = loader ? defineAsyncComponent(loader) : undefined
    }
    if (typeof _component === 'string') {
      return _component
    }
  }

  if (!_component) {
    return _component
  }

  const componentObject = _component as Renderable
  if ('__asyncLoader' in componentObject) {
    return componentObject
  }

  if ('setup' in componentObject) {
    return defineAsyncComponent(() => Promise.resolve(componentObject as Renderable))
  }

  return componentObject
}

async function scan() {
  if (cache)
    return cache

  const baseURL = nuxt.options.app.baseURL
  const dirs: { layerDir: string, files: string[] }[] = []

  for (const layerDir of layerDirs) {
    const files = await glob(['**/*'], {
      cwd: layerDir,
      onlyFiles: true,
    })
    dirs.push({ layerDir, files })
  }

  const uniquePaths = new Set()
  cache = []

  for (const { layerDir, files } of dirs) {
    for (const path of files) {
      const filePath = resolve(layerDir, path)
      if (!filePath.startsWith(layerDir))
        continue
      const stat = await fsp.lstat(filePath)
      const fullPath = join(baseURL, path)

      // Check if path already exists in uniquePaths set
      if (!uniquePaths.has(fullPath)) {
        cache.push({
          path,
          publicPath: fullPath,
          filePath,
          type: guessType(path),
          size: stat.size,
          mtime: stat.mtimeMs,
          layer: publicDir !== layerDir ? layerDir : undefined,
        })
        uniquePaths.add(fullPath)
      }
    }
  }

  return cache.sort((a, b) => a.path.localeCompare(b.path))
}

export async function resolveProvider(_nuxt: any, key: string, input: InputProvider): Promise<ImageModuleProvider> {
  if (typeof input === 'string') {
    input = { name: key, provider: input }
  }

  if (!input.name) {
    input.name = key
  }

  if (!input.provider) {
    input.provider = input.name
  }

  if (input.provider in normalizableProviders) {
    input.provider = normalizableProviders[input.provider]!()
  }

  input.provider = BuiltInProviders.includes(input.provider as ImageProviderName)
    ? resolver.resolve('./runtime/providers/' + input.provider)
    : await resolvePath(input.provider)

  const setup = input.setup || providerSetup[input.name as ImageProviderName]

  return <ImageModuleProvider> {
    ...input,
    setup,
    runtime: normalize(input.provider!),
    importName: genSafeVariableName(`${key}Runtime$${hash(input.provider)}`),
    runtimeOptions: input.options,
  }
}

function matchBrowserLocale(locales: Locale[], browserLocales: readonly string[]): BrowserLocale[] {
  const matchedLocales: BrowserLocale[] = []

  // first pass: match exact locale.
  for (const [index, browserCode] of browserLocales.entries()) {
    const matchedLocale = locales.find(l => l.language?.toLowerCase() === browserCode.toLowerCase())
    if (matchedLocale) {
      matchedLocales.push({ code: matchedLocale.code, score: 1 - index / browserLocales.length })
      break
    }
  }

  // second pass: match only locale code part of the browser locale (not including country).
  for (const [index, browserCode] of browserLocales.entries()) {
    const languageCode = browserCode.split('-')[0]!.toLowerCase()
    const matchedLocale = locales.find(l => l.language?.split('-')[0]!.toLowerCase() === languageCode)
    if (matchedLocale) {
      // deduct a thousandth for being non-exact match.
      matchedLocales.push({ code: matchedLocale.code, score: 0.999 - index / browserLocales.length })
      break
    }
  }

  return matchedLocales
}

function compareBrowserLocale(a: BrowserLocale, b: BrowserLocale): number {
  if (a.score === b.score) {
    // if scores are equal then pick more specific (longer) code.
    return b.code.length - a.code.length
  }
  return b.score - a.score
}

export function localeHead(
  options: HeadContext,
  currentLanguage = options.getCurrentLanguage(),
  currentDirection = options.getCurrentDirection(),
): I18nHeadMetaInfo {
  const metaObject: I18nHeadMetaInfo = {
    htmlAttrs: {},
    link: [],
    meta: [],
  }

  // Adding Direction Attribute
  if (options.dir) {
    metaObject.htmlAttrs.dir = currentDirection
  }

  if (options.lang && currentLanguage) {
    metaObject.htmlAttrs.lang = currentLanguage
  }

  // Adding SEO Meta
  if (options.seo) {
    const alternateLinks = getHreflangLinks(options)
    metaObject.link = metaObject.link.concat(
      alternateLinks,
      getCanonicalLink(options),
    )

    metaObject.meta = metaObject.meta.concat(
      getOgUrl(options),
      getCurrentOgLocale(options),
      getAlternateOgLocales(
        options,
        strictSeo
          ? alternateLinks.map(x => x.hreflang).filter(x => x !== 'x-default') as string[]
          : options.locales.map(x => x.language || x.code),
      ),
    )
  }

  return metaObject
}

export async function determineCallbackUrl(
  authConfig: AuthRuntimeConfigForCallbackUrl,
  userCallbackUrl: string | undefined,
  inferFromRequest?: boolean | undefined
): Promise<string | undefined> {
  // Priority 1: User setting
  if (userCallbackUrl) {
    return await normalizeCallbackUrl(userCallbackUrl)
  }

  // Priority 2: `addDefaultCallbackUrl`
  const authConfigCallbackUrl = typeof authConfig.globalAppMiddleware === 'object'
    ? authConfig.globalAppMiddleware.addDefaultCallbackUrl
    : undefined

  // If a string value was set, always callback to it
  if (typeof authConfigCallbackUrl === 'string') {
    return await normalizeCallbackUrl(authConfigCallbackUrl)
  }

  // Priority 3: Infer callback URL from the request
  const shouldInferFromRequest = inferFromRequest !== false
    && (
      inferFromRequest === true
      || authConfigCallbackUrl === true
      || (authConfigCallbackUrl === undefined && authConfig.globalAppMiddleware === true)
    )

  if (shouldInferFromRequest) {
    const nuxt = useNuxtApp()
    return getRequestURLWN(nuxt)
  }
}

init(): void {
  this.runtimeConfig = useRuntimeConfig().public.auth
  this.auth = useAuth()

  document.addEventListener('visibilitychange', this.boundVisibilityHandler, false)

  const { enablePeriodically } = this.config

  if (enablePeriodically !== false && enablePeriodically !== undefined) {
    const intervalTime = enablePeriodically === true ? 1000 : safeTimerDelay(enablePeriodically)

    this.refetchIntervalTimer = setInterval(() => {
      if (this.auth?.data.value) {
        this.auth.refresh()
      }
    }, intervalTime)
  }

  const provider = this.runtimeConfig.provider
  if (provider.type === 'local' && provider.refresh.isEnabled && provider.refresh.token?.maxAgeInSeconds) {
    const intervalTime = safeTimerDelay(provider.refresh.token.maxAgeInSeconds * 1000)

    this.refreshTokenIntervalTimer = setInterval(() => {
      if (this.auth?.refreshToken.value) {
        this.auth.refresh()
      }
    }, intervalTime)
  }
}

async function signOut(options?: SignOutOptions) {
  const { callbackUrl: userCallbackUrl, redirect = true } = options ?? {}
  const csrfToken = await getCsrfTokenWithNuxt(nuxt)

  // Determine the correct callback URL
  const callbackUrl = await determineCallbackUrl(
    runtimeConfig.public.auth,
    userCallbackUrl,
    true
  )

  if (!csrfToken) {
    throw createError({ statusCode: 400, message: 'Could not fetch CSRF Token for signing out' })
  }

  const signoutData = await _fetch<{ url: string }>(nuxt, '/signout', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      ...(await getRequestHeaders(nuxt))
    },
    onRequest: ({ options }) => {
      options.body = new URLSearchParams({
        csrfToken: csrfToken as string,
        callbackUrl,
        json: 'true'
      })
    }
  }).catch(error => error.data)

  if (redirect) {
    const url = signoutData.url ?? callbackUrl
    return navigateToAuthPageWN(nuxt, url)
  }

  await getSessionWithNuxt(nuxt)
  return signoutData
}

export function resolveApiBaseURL(runtimeConfig: RuntimeConfig, returnOnlyPathname?: boolean): string {
  const authRuntimeConfig = runtimeConfig.public.auth

  // If the user has not specified `returnOnlyPathname`, infer it automatically.
  // When internal routing is enabled, drop everything except path.
  if (returnOnlyPathname === undefined) {
    returnOnlyPathname = !runtimeConfig.public.auth.disableInternalRouting
  }

  // Default to static runtime config (still overridable using `NUXT_PUBLIC_AUTH_BASE_URL`)
  let baseURL = authRuntimeConfig.baseURL

  // Note: the `server` condition is here because Nuxt explicitly filters out all the env variables for the Client build,
  // thus the check can be safely dropped. Instead of it, the `runtime/plugin` would set the `baseURL` on the runtime config.
  if (import.meta.server !== false && authRuntimeConfig.originEnvKey) {
    // Override base URL using environment variable specified in `originEnvKey` if any.
    // By default, would use `AUTH_ORIGIN`, can be changed by user
    const envBaseURL = process.env[authRuntimeConfig.originEnvKey]
    if (envBaseURL) {
      baseURL = envBaseURL
    }
  }

  if (returnOnlyPathname) {
    baseURL = withLeadingSlash(parseURL(baseURL).pathname)
  }

  return baseURL
}

async run({ args }) {
  if (args.verbose) {
    // Set log level to debug
    consola.level = 4
  }
  const cwd = args.cwd || process.cwd()
  await loadDotenv({ cwd, dotenv: args.dotenv })
  consola.info('Ensuring database migrations are available...')
  await execa({
    stdio: 'pipe',
    preferLocal: true,
    cwd
  })`nuxt prepare`
  consola.info('Applying database migrations...')
  const hubConfig = JSON.parse(await readFile(join(cwd, '.nuxt/hub/db/config.json'), 'utf-8'))
  consola.info(`Database: \`${hubConfig.db.dialect}\` with \`${hubConfig.db.driver}\` driver`)
  const url = hubConfig.db.connection?.uri || hubConfig.db.connection?.url
  if (url) consola.debug(`Database connection: \`${url}\``)
  const hubDir = join(cwd, hubConfig.dir)
  const db = await createDrizzleClient(hubConfig.db, hubDir)
  const migrationsApplied = await applyDatabaseMigrations(hubConfig, db)
  if (migrationsApplied === false) {
    process.exit(1)
  }
  const queriesApplied = await applyDatabaseQueries(hubConfig, db)
  if (queriesApplied === false) {
    process.exit(1)
  }
  await db.$client?.end?.()
}

async function _imageMeta(url: string): Promise<ImageInfo> {
  if (import.meta.server) {
    const imageMeta = await import('image-meta').then(r => r.imageMeta)
    const data: Buffer = await fetch(url).then((res: any) => res.buffer())
    const metadata = imageMeta(data)
    if (!metadata) {
      throw new Error(`No metadata could be extracted from the image \`${url}\`.`)
    }
    const { width, height } = metadata
    const meta = {
      width: width!,
      height: height!,
      ratio: width && height ? width / height : undefined,
    }

    return meta
  }
  if (typeof Image === 'undefined') {
    throw new TypeError('Image not supported')
  }

  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      const meta = {
        width: img.width,
        height: img.height,
        ratio: img.width / img.height,
      }
      resolve(meta)
    }
    img.onerror = err => reject(err)
    img.src = url
  })
}

async ({ request }) => {
  const req = useRequest()
  if (!req.context) {
    throw new Error('Missing Nitro request context')
  }
  const log = requireRequestLogger(req.context)

  const body = await request.json() as { resourceId: string, changes: Record<string, unknown> }

  log.set({
    user: { id: 'user_456', role: 'member' },
    action: 'update_resource',
    resource: { id: body.resourceId, changes: Object.keys(body.changes) },
  })

  await new Promise(resolve => setTimeout(resolve, 100))
  log.set({ validation: { passed: true, checks: ['schema', 'constraints'] } })

  await new Promise(resolve => setTimeout(resolve, 80))
  log.set({ permissions: { checked: true, hasUpdate: false, requiredRole: 'admin' } })

  throw createError({
    message: 'Insufficient permissions',
    status: 403,
    why: 'Role "member" cannot update resources — requires "admin" role',
    fix: 'Request admin privileges from your team lead or contact support',
    link: 'https://docs.example.com/permissions/roles',
  })
}

async ({ request }) => {
  const req = useRequest()
  if (!req.context) {
    throw new Error('Missing Nitro request context')
  }
  const log = requireRequestLogger(req.context)

  const body = await request.json() as {
    userId: string
    plan: string
    items: { name: string, price: number }[]
    coupon?: string
  }

  log.set({
    user: { id: body.userId, plan: body.plan },
  })

  await new Promise(resolve => setTimeout(resolve, 60))
  const total = body.items.reduce((sum, item) => sum + item.price, 0)
  log.set({
    cart: {
      items: body.items.length,
      total,
      currency: 'USD',
      ...(body.coupon && { coupon: body.coupon, discount: Math.round(total * 0.25) }),
    },
  })

  await new Promise(resolve => setTimeout(resolve, 80))
  log.set({
    payment: { method: 'card', cardBrand: 'visa', cardLast4: '4242' },
    fraud: { score: 85, riskLevel: 'high', passed: false },
  })

  throw createError({
    message: 'Payment failed',
    status: 402,
    why: 'Transaction flagged by fraud detection (risk score: 85/100)',
    fix: 'Verify your billing address matches your card, or try a different payment method',
    link: 'https://docs.example.com/payments/fraud-prevention',
  })
}

async init(): Promise<void> {
  // Reset on error
  if (this.options.resetOnError) {
    this.onError((...args) => {
      if (
        typeof this.options.resetOnError !== 'function' ||
        this.options.resetOnError(...args)
      ) {
        this.reset()
      }
    })
  }

  // Restore strategy
  this.$storage.syncUniversal('strategy', this.options.defaultStrategy)

  // Set default strategy if current one is invalid
  if (!this.getStrategy(false)) {
    this.$storage.setUniversal('strategy', this.options.defaultStrategy)

    // Give up if still invalid
    if (!this.getStrategy(false)) {
      return Promise.resolve()
    }
  }

  try {
    // Call mounted for active strategy on initial load
    await this.mounted()
  } catch (error) {
    this.callOnError(error)
  } finally {
    // Watch for loggedIn changes only in client side
    if (process.client && this.options.watchLoggedIn) {
      this.$storage.watchState('loggedIn', (loggedIn) => {
        if (
          // TODO: Why Router is incompatible?
          !routeOption(this.ctx.route as unknown as Route, 'auth', false)
        ) {
          this.redirect(loggedIn ? 'home' : 'logout')
        }
      })
    }
  }
}

fetchUser(endpoint?: HTTPRequest): Promise<HTTPResponse | void> {
  // Token is required but not available
  if (!this.check().valid) {
    return Promise.resolve()
  }

  // User endpoint is disabled
  if (!this.options.endpoints.user) {
    this.$auth.setUser({})
    return Promise.resolve()
  }

  // Try to fetch user and then set
  return this.$auth
    .requestWith(this.name, endpoint, this.options.endpoints.user)
    .then((response) => {
      const userData = getProp(response.data, this.options.user.property)

      if (!userData) {
        const error = new Error(
          `User Data response does not contain field ${this.options.user.property}`
        )
        return Promise.reject(error)
      }

      this.$auth.setUser(userData)
      return response
    })
    .catch((error) => {
      this.$auth.callOnError(error, { method: 'fetchUser' })
      return Promise.reject(error)
    })
}

async refreshTokens(): Promise<HTTPResponse | void> {
  // Get refresh token
  const refreshToken = this.refreshToken.get()

  // Refresh token is required but not available
  if (!refreshToken) {
    return
  }

  // Get refresh token status
  const refreshTokenStatus = this.refreshToken.status()

  // Refresh token is expired. There is no way to refresh. Force reset.
  if (refreshTokenStatus.expired()) {
    this.$auth.reset()

    throw new ExpiredAuthSessionError()
  }

  // Delete current token from the request header before refreshing
  this.requestHandler.clearHeader()

  const response = await this.$auth
    .request({
      method: 'post',
      url: this.options.endpoints.token,
      baseURL: '',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      data: encodeQuery({
        refresh_token: removeTokenPrefix(
          refreshToken,
          this.options.token.type
        ),
        scopes: this.scope,
        client_id: this.options.clientId + '',
        grant_type: 'refresh_token'
      })
    })
    .catch((error) => {
      this.$auth.callOnError(error, { method: 'refreshToken' })
      return Promise.reject(error)
    })

  this.updateTokens(response)

  return response
}

export function createCLI(opts: CLIOptions) {
  const main = defineCommand({
    meta: {
      name: opts.name,
      description: opts.description,
    },
    args: {
      dir: {
        type: 'positional',
        description: 'Project directory',
        required: false,
        default: 'docs',
      },
      template: {
        type: 'string',
        alias: 't',
        description: 'Template to use (default, i18n)',
        required: false,
        default: 'default',
      },
    },
    async setup(context) {
      const dir = resolve(context.args.dir as string)
      const template = context.args.template as 'i18n' | 'default'

      if (!['i18n', 'default'].includes(template)) {
        throw new Error('Invalid template')
      }

      const { runCommand } = await import('@nuxt/cli')
      await runCommand('init', [dir, '-t', `gh:nuxt-content/docus/.starters/${template}`])
    },
  })

  return {
    runMain: () => runMain(main),
  }
}

export async function copyDatabaseAssets(nitro: Nitro, hub: ResolvedHubConfig) {
  if (!hub.db) return

  const migrationsPath = join(hub.dir, 'db/migrations')
  const queriesPath = join(hub.dir, 'db/queries')
  const outputDir = nitro.options.output.serverDir

  const bundledItems = []

  try {
    // copy migrations if they exist
    await cp(migrationsPath, resolve(outputDir, 'db/migrations'), { recursive: true })
    bundledItems.push('migrations')
  } catch (error: unknown) {
    if ((error as NodeJS.ErrnoException).code === 'ENOENT') {
      log.info('No local database migrations found')
    } else {
      console.error('Error copying migrations:', error)
    }
  }

  try {
    // copy queries if they exist
    await cp(queriesPath, resolve(outputDir, 'db/queries'), { recursive: true })
    bundledItems.push('queries')
  } catch (error: unknown) {
    if ((error as NodeJS.ErrnoException).code === 'ENOENT') {
      log.info('No local database queries found')
    } else {
      console.error('Error copying queries:', error)
    }
  }

  if (bundledItems.length > 0) {
    log.info(`Database ${bundledItems.join(' and ')} included in build`)
  }
}
